const REGLES_BASE = {
  grilleForfait: [
    { kmMax: 30, prix: 250 }, { kmMax: 40, prix: 320 }, { kmMax: 50, prix: 350 },
    { kmMax: 60, prix: 390 }, { kmMax: 70, prix: 430 }, { kmMax: 80, prix: 500 },
    { kmMax: 90, prix: 540 }, { kmMax: 100, prix: 580 }, { kmMax: 110, prix: 620 },
    { kmMax: 120, prix: 660 }, { kmMax: 130, prix: 700 }, { kmMax: 140, prix: 740 },
    { kmMax: 150, prix: 780 }, { kmMax: 160, prix: 820 }, { kmMax: 170, prix: 860 },
    { kmMax: 180, prix: 900 },
  ],
  seuilForfait: 180,
  facteurTrajetVehicule: 2,
  tarifKmAuDela: 2.5,
  capaciteMaxAuto: 85,
  modeCoefficients: "multiplicatif",
};

const MOIS_NIVEAU = {
  1: "basse", 2: "basse", 8: "basse", 11: "basse",
  9: "moyenne", 10: "moyenne", 12: "moyenne",
  3: "haute", 4: "haute", 7: "haute",
  5: "tres_haute", 6: "tres_haute",
};

const round2 = (n) => Math.round((n + Number.EPSILON) * 100) / 100;
function joursEntre(d1, d2) { return Math.round((new Date(d2) - new Date(d1)) / 86400000); }
function baseTransfertSimple(km, r) {
  if (km <= r.seuilForfait) {
    const p = r.grilleForfait.find((g) => km <= g.kmMax);
    return (p || r.grilleForfait[0]).prix;
  }
  return km * r.facteurTrajetVehicule * r.tarifKmAuDela;
}

function buildRegles(rows) {
  const get = (type, val) => {
    const r = rows.find((x) => x.type_critere === type && x.valeur_critere === val);
    if (!r || r.coefficient == null) {
      throw new Error(`Règle manquante dans la Matrice : ${type}/${val}`);
    }
    return r.coefficient;
  };

  const saisonnalite = {};
  for (const [mois, niveau] of Object.entries(MOIS_NIVEAU)) {
    saisonnalite[mois] = { niveau, coef: get("saison", niveau) };
  }

  const dateDepart = [
    { joursMax: 14, code: "DD_PRIORITAIRE", coef: get("date_depart", "DD_PRIORITAIRE") },
    { joursMax: 30, code: "DD_URGENT", coef: get("date_depart", "DD_URGENT") },
    { joursMax: 90, code: "DD_NORMAL", coef: get("date_depart", "DD_NORMAL") },
    { joursMax: Infinity, code: "DD_3MOISETPLUS", coef: get("date_depart", "DD_3MOISETPLUS") },
  ];

  const capacite = [
    { paxMax: 19, coef: get("capacite", "<=19") },
    { paxMax: 53, coef: get("capacite", "19-53") },
    { paxMax: 63, coef: get("capacite", "53-63") },
    { paxMax: 67, coef: get("capacite", "63-67") },
    { paxMax: 85, coef: get("capacite", "67-85") },
  ];

  return {
    ...REGLES_BASE,
    saisonnalite,
    dateDepart,
    capacite,
    tarifGuideParJour: get("option", "guide_par_jour"),
    tarifNuitChauffeur: get("option", "nuit_chauffeur"),
    marge: get("option", "marge"),
    tva: get("option", "tva"),
  };
}

function calculerDevis(entree, regles) {
  const {
    distance_km, aller_retour = false, date_depart,
    date_demande = new Date().toISOString().slice(0, 10),
    nb_passagers, guide_jours = 0, nuits_chauffeur = 0, peages = 0,
  } = entree || {};

  const manquants = [];
  if (!(distance_km > 0)) manquants.push("distance_km");
  if (!date_depart) manquants.push("date_depart");
  if (!(nb_passagers > 0)) manquants.push("nb_passagers");
  if (manquants.length) {
    return { status: "erreur", raison: `Données manquantes/invalides : ${manquants.join(", ")}` };
  }

  if (nb_passagers > regles.capaciteMaxAuto) {
    return { status: "manuel", raison: `Capacité ${nb_passagers} > ${regles.capaciteMaxAuto} passagers — envoi au commercial (flux manuel).` };
  }

  const baseSimple = baseTransfertSimple(distance_km, regles);
  const baseTrajet = aller_retour ? baseSimple * 2 : baseSimple;

  const mois = new Date(date_depart).getMonth() + 1;
  const saison = regles.saisonnalite[mois] || { niveau: "inconnue", coef: 0 };
  const jours = joursEntre(date_demande, date_depart);
  const regleDate = regles.dateDepart.find((r) => jours <= r.joursMax);
  const regleCap = regles.capacite.find((c) => nb_passagers <= c.paxMax);

  const s = saison.coef, d = regleDate.coef, c = regleCap.coef;

  let transportAjuste;
  if (regles.modeCoefficients === "additif") transportAjuste = baseTrajet * (1 + s + d + c);
  else transportAjuste = baseTrajet * (1 + s) * (1 + d) * (1 + c);

  const optGuide = guide_jours * regles.tarifGuideParJour;
  const optNuit = nuits_chauffeur * regles.tarifNuitChauffeur;
  const optionsTotal = optGuide + optNuit + peages;
  const sousTotal = transportAjuste + optionsTotal;

  const montantHt = sousTotal * (1 + regles.marge);
  const montantTva = montantHt * regles.tva;
  const montantTtc = montantHt + montantTva;

  const pct = (x) => `${x >= 0 ? "+" : ""}${(x * 100).toFixed(0)}%`;
  const lignes_detail = [
    `Base transfert simple (${distance_km} km) : ${round2(baseSimple)} €`,
    aller_retour ? `Aller/retour (x2) : ${round2(baseTrajet)} €` : `Aller simple : ${round2(baseTrajet)} €`,
    `Saisonnalité (${saison.niveau}) : ${pct(s)}`,
    `Date demande/départ (${regleDate.code}, ${jours} j) : ${pct(d)}`,
    `Capacité (${nb_passagers} pax) : ${pct(c)}`,
    `Transport ajusté : ${round2(transportAjuste)} €`,
    optGuide ? `Guide : ${guide_jours} j x ${regles.tarifGuideParJour} € = ${round2(optGuide)} €` : null,
    optNuit ? `Nuit(s) chauffeur : ${nuits_chauffeur} x ${regles.tarifNuitChauffeur} € = ${round2(optNuit)} €` : null,
    peages ? `Péages (forfait) : ${round2(peages)} €` : null,
    `Sous-total HT avant marge : ${round2(sousTotal)} €`,
    `Marge (${pct(regles.marge)}) : ${round2(montantHt - sousTotal)} €`,
    `MONTANT HT : ${round2(montantHt)} €`,
    `TVA (${pct(regles.tva)}) : ${round2(montantTva)} €`,
    `MONTANT TTC : ${round2(montantTtc)} €`,
  ].filter(Boolean).join("\n");

  return {
    status: "ok",
    montant_ht: round2(montantHt),
    montant_ttc: round2(montantTtc),
    montant_tva: round2(montantTva),
    detail: {
      distance_km, aller_retour,
      base_simple: round2(baseSimple), base_trajet: round2(baseTrajet),
      saison: { niveau: saison.niveau, coef: s },
      date: { code: regleDate.code, coef: d, jours_avant_depart: jours },
      capacite: { coef: c },
      transport_ajuste: round2(transportAjuste),
      options: { guide: round2(optGuide), nuit_chauffeur: round2(optNuit), peages: round2(peages), total: round2(optionsTotal) },
      sous_total_ht: round2(sousTotal),
      marge_montant: round2(montantHt - sousTotal),
    },
    lignes_detail,
  };
}

// ================= EXÉCUTION DANS n8n =================
// 1) Lignes de la Matrice depuis Airtable
const matriceRows = $('Search records').all().map((i) => i.json);

// 2) Données du trajet depuis le trigger
const entree = $('When Executed by Another Workflow').first().json;

// 3) Distance depuis le sous-workflow calculer_distance
const distanceData = $("Call 'calculer_distance'").first().json;
entree.distance_km = distanceData.distance_km;

// 4) Garde-fou : si la distance est absente ou invalide, on stoppe proprement
if (!entree.distance_km || entree.distance_km <= 0) {
  return [{ json: { status: "erreur", raison: "Distance non calculée (ville introuvable ?)" } }];
}

// 5) Construit les règles + calcule
const regles = buildRegles(matriceRows);
const resultat = calculerDevis(entree, regles);

return [{ json: resultat }];
